import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"血色披风","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/血色披风.md","filePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/血色披风.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/3.B级/血色披风.md"};function l(p,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"血色披风",tabindex:"-1"},[s("血色披风 "),e("a",{class:"header-anchor",href:"#血色披风","aria-label":'Permalink to "血色披风"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="血色披风-1" tabindex="-1">血色披风 <a class="header-anchor" href="#血色披风-1" aria-label="Permalink to &quot;血色披风&quot;">​</a></h1><p>血色披风<br> B+2000<br> 本质：魔幻<br> 占据：披风位<br> 血色披风是出自虚天殿的藏宝阁的上古法宝，其造型奇特之极，竟有两层构成。里面是银色丝线编制而成，外面则是一根根奇异的不知名羽毛飞贴上面。这些羽毛在光罩中变幻出暗红的血光，显得诡异之极。在注入法力后可化作猩红血光，可成倍的提高遁速，虽然操控不甚灵活，但其提供的遁速使得金丹期修士穿戴后，拥有不下于元婴期修士的逃遁速度。</p><p>被动：穿戴后获得机动性为完美的飞行能力，飞行速度等同于穿戴者的基础速度。</p><p>主动：每轮一次，穿戴者注入5点东方能量（真气/内力/气/炁）,此刻，披风血色的光芒大盛起来，似被一股火热的感觉包裹，披风外层的数十根羽毛同时幻化出根根的血色长翎，整件披风都被一团浓浓的血光罩在了其中。穿戴者立刻以自由动作（不是你的回合则是反射动作）进行一次移动，该次移动的最大距离为：你的基础速度*2倍+50米。但本次移动的机动性下降为笨拙，此时，人物在感知属性上每有1点附加成功，则该次移动的机动性上升一级（笨拙-普通-灵活-完美），最高为完美。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
